module.exports = "<!-- ══ Header ══════════════════════════════════════════════════ -->\n<ds-header>\n\n  <!-- Logo Qirin (reversed = blanc sur fond brand) -->\n  <ds-logo slot=\"logo\" [reversed]=\"true\" />\n\n  <!-- Navigation tabs -->\n  <ng-container slot=\"tabs\">\n    <ds-tab tone=\"reversed\" [selected]=\"true\">Home</ds-tab>\n    <ds-tab tone=\"reversed\">Buyers</ds-tab>\n    <ds-tab tone=\"reversed\">Policies</ds-tab>\n    <ds-tab tone=\"reversed\">Tools</ds-tab>\n    <ds-tab tone=\"reversed\">Configuration</ds-tab>\n  </ng-container>\n\n  <!-- Action icons -->\n  <ng-container slot=\"actions\">\n    <ds-button-icon type=\"tertiary\" [reversed]=\"true\" size=\"s\" ariaLabel=\"Rechercher\">\n      <ds-icon name=\"search\" [size]=\"16\" />\n    </ds-button-icon>\n    <ds-button-icon type=\"tertiary\" [reversed]=\"true\" size=\"s\" ariaLabel=\"Aide\">\n      <ds-icon name=\"help\" [size]=\"16\" />\n    </ds-button-icon>\n    <ds-button-icon type=\"tertiary\" [reversed]=\"true\" size=\"s\" ariaLabel=\"Notifications\">\n      <ds-icon name=\"bell\" [size]=\"16\" />\n    </ds-button-icon>\n  </ng-container>\n\n  <!-- Account -->\n  <ng-container slot=\"account\">\n    <ds-tab tone=\"reversed\">John Doe</ds-tab>\n  </ng-container>\n\n</ds-header>\n\n<!-- ══ Layout principal ════════════════════════════════════════ -->\n<div class=\"home-layout\">\n\n  <!-- ── Main content ────────────────────────────────────────── -->\n  <main class=\"home-main\">\n\n    <!-- Hero section -->\n    <section class=\"home-hero\">\n      <div class=\"home-hero__content\">\n        <p class=\"home-hero__welcome\">Welcome back, John</p>\n        <h1 class=\"home-hero__title\">What would you like<br>to work on today?</h1>\n        <p class=\"home-hero__subtitle\">\n          Pick an action below to get started, or explore your dashboard\n          for a complete overview of your activity.\n        </p>\n        <ds-search-bar\n          placeholder=\"Search for a buyer\"\n          buttonLabel=\"Search\"\n          [(value)]=\"searchValue\"\n          [recentSearches]=\"recentSearches\"\n          (search)=\"onSearch($event)\"\n          (recentSelect)=\"onRecentSelect($event)\"\n        />\n      </div>\n\n      <!-- Illustration décorative -->\n      <app-hero-illustration />\n    </section>\n\n    <!-- Action cards -->\n    <section class=\"home-actions\">\n      @for (card of actionCards; track card.title) {\n        <ds-action-card\n          [title]=\"card.title\"\n          [description]=\"card.description\"\n          [linkLabel]=\"card.linkLabel\"\n        >\n          <ds-icon slot=\"icon\" [name]=\"card.icon\" [size]=\"24\" />\n        </ds-action-card>\n      }\n    </section>\n\n  </main>\n</div>\n";

